/**
 * Geolocation utilities for Next.js middleware and edge functions.
 *
 * Extracts geolocation data from common CDN/proxy headers
 * (Vercel, Cloudflare) and provides helpers for region checking
 * and distance calculation.
 */

export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

function headerOrUndefined(
  headers: Headers,
  name: string
): string | undefined {
  const value = headers.get(name)
  return value === null ? undefined : value
}

/**
 * Extracts geolocation data from request headers.
 *
 * Reads Vercel `x-vercel-ip-*` headers with a Cloudflare
 * `cf-ipcountry` fallback for `countryCode`. City names are
 * URL-decoded (Vercel sends them percent-encoded).
 */
export function geoFromHeaders(headers: Headers): Geo {
  const rawCity = headerOrUndefined(headers, 'x-vercel-ip-city')
  const city =
    rawCity !== undefined ? decodeURIComponent(rawCity) : undefined

  const countryCode =
    headerOrUndefined(headers, 'x-vercel-ip-country') ??
    headerOrUndefined(headers, 'cf-ipcountry')

  const country =
    countryCode !== undefined
      ? COUNTRY_NAMES[countryCode.toUpperCase()]
      : undefined

  const region = headerOrUndefined(
    headers,
    'x-vercel-ip-country-region'
  )
  const latitude = headerOrUndefined(headers, 'x-vercel-ip-latitude')
  const longitude = headerOrUndefined(headers, 'x-vercel-ip-longitude')
  const timezone = headerOrUndefined(headers, 'x-vercel-ip-timezone')

  return { city, country, countryCode, region, latitude, longitude, timezone }
}

/**
 * Extracts geolocation data from a request object.
 *
 * Convenience wrapper around {@link geoFromHeaders} that accepts any
 * object with a `headers` property (e.g. `NextRequest`).
 */
export function geo(req: { headers: Headers }): Geo {
  return geoFromHeaders(req.headers)
}

/**
 * Checks whether the given geolocation falls within a list of regions.
 *
 * Comparison is case-insensitive on `geo.countryCode`.
 *
 * @returns `true` if `geo.countryCode` matches any entry in `regions`.
 */
export function isInRegion(geoData: Geo, regions: string[]): boolean {
  if (geoData.countryCode === undefined) {
    return false
  }
  const code = geoData.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

/**
 * Calculates the great-circle distance between two points using the
 * Haversine formula.
 *
 * @returns Distance in kilometres.
 */
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth radius in km
  const toRad = (deg: number) => (deg * Math.PI) / 180

  const φ1 = toRad(parseFloat(lat1))
  const φ2 = toRad(parseFloat(lat2))
  const Δφ = toRad(parseFloat(lat2) - parseFloat(lat1))
  const Δλ = toRad(parseFloat(lon2) - parseFloat(lon1))

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2)

  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

  return R * c
}

const geoExports = {
  geo: require('next/dist/server/web/spec-extension/geo').geo,
  geoFromHeaders:
    require('next/dist/server/web/spec-extension/geo').geoFromHeaders,
  isInRegion: require('next/dist/server/web/spec-extension/geo').isInRegion,
  geoDistance: require('next/dist/server/web/spec-extension/geo').geoDistance,
}

// https://nodejs.org/api/esm.html#commonjs-namespaces
// When importing CommonJS modules, the module.exports object is provided as the default export
module.exports = geoExports

// make import { xxx } from 'next/geo' work
exports.geo = geoExports.geo
exports.geoFromHeaders = geoExports.geoFromHeaders
exports.isInRegion = geoExports.isInRegion
exports.geoDistance = geoExports.geoDistance

import { describe, it, expect } from '@jest/globals'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

describe('geo()', () => {
  it('extracts geolocation from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'San%20Francisco',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })

    const result = geo({ headers })
    expect(result.city).toBe('San Francisco')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('CA')
    expect(result.latitude).toBe('37.7749')
    expect(result.longitude).toBe('-122.4194')
    expect(result.timezone).toBe('America/Los_Angeles')
  })

  it('returns undefined fields when headers are missing', () => {
    const result = geo({ headers: new Headers() })
    expect(result.city).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })
})

describe('geoFromHeaders()', () => {
  it('falls back to Cloudflare cf-ipcountry header', () => {
    const headers = new Headers({
      'cf-ipcountry': 'GB',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
  })

  it('prefers Vercel header over Cloudflare fallback', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'DE',
      'cf-ipcountry': 'FR',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('URL-decodes city names', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'S%C3%A3o%20Paulo',
    })

    const result = geoFromHeaders(headers)
    expect(result.city).toBe('São Paulo')
  })

  it('returns undefined country name for unknown country codes', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'ZZ',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })
})

describe('country name lookup', () => {
  it.each([
    ['US', 'United States'],
    ['GB', 'United Kingdom'],
    ['DE', 'Germany'],
    ['FR', 'France'],
    ['JP', 'Japan'],
    ['CN', 'China'],
    ['IN', 'India'],
    ['BR', 'Brazil'],
    ['AU', 'Australia'],
    ['CA', 'Canada'],
  ])('maps %s to %s', (code, name) => {
    const headers = new Headers({ 'x-vercel-ip-country': code })
    const result = geoFromHeaders(headers)
    expect(result.country).toBe(name)
  })
})

describe('isInRegion()', () => {
  it('returns true when countryCode matches a region', () => {
    expect(isInRegion({ countryCode: 'US' }, ['US', 'CA'])).toBe(true)
  })

  it('performs case-insensitive comparison', () => {
    expect(isInRegion({ countryCode: 'us' }, ['US', 'CA'])).toBe(true)
    expect(isInRegion({ countryCode: 'US' }, ['us', 'ca'])).toBe(true)
  })

  it('returns false when countryCode does not match', () => {
    expect(isInRegion({ countryCode: 'GB' }, ['US', 'CA'])).toBe(false)
  })

  it('returns false when countryCode is undefined', () => {
    expect(isInRegion({}, ['US', 'CA'])).toBe(false)
  })
})

describe('geoDistance()', () => {
  it('calculates New York to London distance (~5570 km)', () => {
    // New York: 40.7128° N, 74.0060° W
    // London:   51.5074° N, 0.1278° W
    const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(distance).toBeGreaterThan(5520)
    expect(distance).toBeLessThan(5620)
  })

  it('returns 0 for the same point', () => {
    const distance = geoDistance('0', '0', '0', '0')
    expect(distance).toBe(0)
  })

  it('calculates antipodal distance (~20015 km)', () => {
    // North pole to south pole
    const distance = geoDistance('90', '0', '-90', '0')
    expect(distance).toBeGreaterThan(20000)
    expect(distance).toBeLessThan(20030)
  })
})
